B.a_8=new A.hG("A konyhai hullad\xe9kot komposzt\xe1lhat\xf3 szemeteszacsk\xf3ba vagy leboml\xf3 zacsk\xf3ba tehetem?","Nem. A komposzt\xe1lhat\xf3 vagy leboml\xf3 zacsk\xf3k nem haszn\xe1lhat\xf3k a gy\u0171jt\xe9s sor\xe1n, mert akad\xe1lyozz\xe1k a konyhai z\xf6ld- \xe9s \xe9lelmiszerhullad\xe9k \xfajrahasznos\xedt\xe1s\xe1t a v\xe9gpontokon. A hullad\xe9kot, k\xe9rj\xfck, csomagol\xe1s n\xe9lk\xfcl helyezd a gy\u0171jt\u0151ed\xe9nybe.")
B.a_c=new A.hG("Milyen k\xf6lts\xe9ge van a barna kuka elsz\xe1ll\xedt\xe1s\xe1nak?","A szolg\xe1ltat\xe1s a k\xf6zszolg\xe1ltat\xe1s r\xe9sze, \xedgy nem ker\xfcl tov\xe1bbi d\xedj kisz\xe1ml\xe1z\xe1sra a barna kuka haszn\xe1lata kapcs\xe1n.")
B.a_5=new A.hG("Nem okoz kellemetlen szagot az ed\xe9nybe helyezett \xe9telmarad\xe9k? Hogyan m\u0171k\xf6dik az ed\xe9nyek mos\xe1sa?","Az \xfaj konyhai z\xf6ld-, \xe9s \xe9lelmiszerhullad\xe9kgy\u0171jt\u0151 ed\xe9nyek szag- \xe9s kifoly\xe1smentesen z\xe1rhat\xf3k. Az ed\xe9nyeket a ter\xfcleti szolg\xe1ltat\xf3 havi egy alkalommal a szolg\xe1ltat\xe1s r\xe9szek\xe9nt az \xfcr\xedt\xe9s ut\xe1n kimossa, ezen fel\xfcli mos\xe1st d\xedj ellen\xe9ben lehet n\xe1luk ig\xe9nyelni.")
B.a_6=new A.hG("Honnan tudom beszerezni a konyhai z\xf6ld-, \xe9s \xe9lelmiszer gy\u0171jt\u0151 kis v\xf6dr\xf6t (Morzsit)?","A t\xe1rsash\xe1zi k\xf6z\xf6s k\xe9pviselet tudja megig\xe9nyelni a Ter\xfcleti Szolg\xe1ltat\xf3n\xe1l. K\xe9rj\xfck ellen\u0151rizze, hogy a szolg\xe1ltat\xe1si ter\xfclethez tartozik-e. T\xe1rsash\xe1z nev\xe9ben csak a k\xf6z\xf6s k\xe9pviselet tud elj\xe1rni, \xedgy mag\xe1nszem\xe9lyk\xe9nt nem ig\xe9nyelhet\u0151 az ed\xe9ny \u2014 k\xe9rj\xfck besz\xe9ljen k\xf6z\xf6s k\xe9pvisel\u0151j\xe9vel.")
B.a_a=new A.hG("Az \xe9n v\xe1rosomban/ker\xfcletemben mikor lesz el\xe9rhet\u0151 a konyhai hullad\xe9k elk\xfcl\xf6n\xedtett gy\u0171jt\xe9se?","A rendszer b\u0151v\xedt\xe9s\xe9n a jelenlegi rendszer tapasztalatai alapj\xe1n folyamatosan dolgozunk. A rendszer b\u0151v\xedt\xe9se eset\xe9n a ter\xfcleti szolg\xe1ltat\xf3 fel fogja venni a k\xf6z\xf6s k\xe9pvisel\u0151kkel a kapcsolatot.")
B.a_b=new A.hG("Bevezet\xe9skor \xe9rtes\xedtik-e a t\xe1rsash\xe1zak k\xf6z\xf6sk\xe9pvisel\u0151it?","Azokon a ter\xfcleteken, ahol bevezet\xe9sre ker\xfcl a gy\u0171jt\xe9s, a ter\xfcleti szolg\xe1ltat\xf3 fel fogja venni a k\xf6z\xf6s k\xe9pvisel\u0151kkel a kapcsolatot az ed\xe9ny kioszt\xe1sa c\xe9lj\xe1b\xf3l.")
B.a_d=new A.hG("Csal\xe1di h\xe1zak r\xe9sz\xe9re mikor lesz el\xe9rhet\u0151 a konyhai hullad\xe9kgy\u0171jt\xe9s?","Csal\xe1di h\xe1zak eset\xe9ben nem el\xe9rhet\u0151 a h\xe1zhoz men\u0151 gy\u0171jt\xe9s, azonban az al\xe1bbi hullad\xe9kudvarokban leadhat\xf3 a konyhai \xe9lelmiszerhullad\xe9k is.")
B.a_7=new A.hG("A szolg\xe1ltat\xe1ssal kapcsolatban van probl\xe9m\xe1m. Kihez fordulhatok?","K\xe9rj\xfck, hogy a szolg\xe1ltat\xe1ssal kapcsolatos k\xe9rd\xe9seivel/\xe9szrev\xe9teleivel forduljon a Ter\xfcleti Szolg\xe1ltat\xf3j\xe1nak \xfcgyf\xe9lszolg\xe1lat\xe1hoz.")
B.a_9=new A.hG("Miben helyezzem ki a kerti z\xf6ld hullad\xe9kot?","A kerti z\xf6ldhullad\xe9k gy\u0171jt\xe9s r\xe9szletes szab\xe1lyai a k\xf6zszolg\xe1ltat\xe1sra vonatkoz\xf3 \xc1SZF-\xfcnkben \xe9rhet\u0151k el, melyet megtal\xe1l a honlapon.")
